{
  "plan": [
    {
      "tool": "iam.check_permission",
      "arguments": {
        "user_id": "{{user_id}}",
        "permission": "iam:read",
        "resource": "iam://roles/{{user_id}}"
      },
      "depends_on": []
    },
    {
      "tool": "sql.snowflake.query",
      "arguments": {
        "query": "SELECT user_id, permission, resource, action, result FROM access_log_facts WHERE user_id IS NOT NULL ORDER BY access_time DESC LIMIT 100"
      },
      "depends_on": [1]
    },
    {
      "tool": "mongo.find",
      "arguments": {
        "collection": "workflow_approvals",
        "filter": {
          "user_id": "{{user_id}}",
          "status": "pending",
          "approval_type": "manager_approval"
        },
        "projection": {
          "workflow_id": 1,
          "approver_id": 1,
          "requested_role": 1,
          "requested_resource": 1,
          "submitted_at": 1,
          "status": 1,
          "expiry": 1
        },
        "sort": {
          "submitted_at": -1
        }
      },
      "depends_on": [1]
    },
    {
      "tool": "sql.postgres.query",
      "arguments": {
        "query": "SELECT wa.workflow_id, wa.status, wa.approver_email, wa.approved_at, wa.comments, u.display_name AS manager_name FROM workflow_approvals wa JOIN users u ON u.user_id = wa.approver_id WHERE wa.user_id = '{{user_id}}' AND wa.status IN ('pending', 'approved') ORDER BY wa.submitted_at DESC LIMIT 1"
      },
      "depends_on": [3]
    },
    {
      "tool": "audit.log_action",
      "arguments": {
        "action": "ACCESS_PROVISIONING_INITIATED",
        "actor": "orchestration-service",
        "target_user": "{{user_id}}",
        "details": {
          "iam_permission_check": "$1.result",
          "snowflake_access_log_count": "$2.row_count",
          "pending_workflow_records": "$3.results",
          "manager_approval_record": "$4.rows"
        },
        "timestamp": "{{current_timestamp}}"
      },
      "depends_on": [4]
    },
    {
      "tool": "iam.grant_role",
      "arguments": {
        "user_id": "{{user_id}}",
        "role": "$3.results[0].requested_role",
        "resource": "$3.results[0].requested_resource",
        "justification": "Manager approval confirmed via workflow_id: $4.rows[0].workflow_id",
        "approved_by": "$4.rows[0].approver_email",
        "approval_timestamp": "$4.rows[0].approved_at"
      },
      "depends_on": [5]

